@immutable
class AppStoreProduct extends SK2Product {
  AppStoreProduct({
    required this.planType,
    required this.productDetails,
    required this.aiCoachCount,
    required this.ballCount,
    required super.id,
    required super.displayName,
    required super.displayPrice,
    required super.description,
    required super.price,
    required super.type,
    required super.priceLocale,
    super.subscription,
  });

  final PlanType planType;
  final ProductDetails productDetails;

  final int? aiCoachCount;
  final int? ballCount;
}

enum PlanType {
  light,
  standard,
  premium,
  // teamType.multiple 用のプランで IAP のサブスクで管理されていない
  forMultipleTeam,
  ;

  static PlanType fromName(String name) {
    return switch (name) {
      'light' || 'Light' => PlanType.light,
      'standard' || 'Standard' => PlanType.standard,
      'premium' || 'Premium' => PlanType.premium,
      _ => PlanType.forMultipleTeam,
    };
  }

  @visibleForTesting
  String get id {
    return switch (this) {
      PlanType.light => '00000001-0000-0050-0000-000000000000',
      PlanType.standard => '00000001-0000-0100-0000-000000000000',
      PlanType.premium => '00000001-0000-0300-0000-000000000000',
      PlanType.forMultipleTeam => '00000001-0000-0300-0000-000000000000',
    };
  }
}

